test_cases.python_test_script:
def test_tc_gw_op_001_message_present(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs, 'GW_OperationalPresence not detected'

def test_tc_gw_op_002_periodic(can_bus):
    msgs = collect_gw_messages(can_bus, 5.0)
    assert len(msgs) >= 3, 'Insufficient periodic messages detected'

def test_tc_gw_op_004_status_active(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert get_gateway_status(msg.data) == 1

def test_tc_gw_op_005_dlc(can_bus):
    msgs = collect_gw_messages(can_bus, 2.0)
    assert msgs
    for msg in msgs:
        assert msg.dlc == GW_OPERATIONAL_PRESENCE_DLC
